#include <stdio.h>
#include <stdint.h>
#include <time.h>
#include <stdlib.h>

#define u32 uint32_t
#define ROCK 1
#define PAPER 2
#define SCISSORS 3

void destemine_winner(u32 player_move, u32 computer_move)
{
	//首先排除平局的情况
	if (player_move == computer_move) {
		puts("平局！");
		return;
	}

	//定义一个胜利的规则映射，其中键是玩家的移动，值是玩家移动可以打败计算机的移动

	u32 winning_moves[4] = { 0, SCISSORS, ROCK, PAPER };
	//0是占位符

	//winning_moves[1] SCISSORS
	//ROCK == 1
	//PAPER == 2
	//SCISSORS == 3

	//这里player_move是玩家的移动，winning_moves[player_move]这个是可以打败计算机的移动
	//比如说玩家选1，只有当计算机选3时才会输，那么就将winning_moves中的winning_moves[1]设置位3
	if (computer_move == winning_moves[player_move]) {
		puts("你赢了！");
	}
	else {
		puts("你输了！");
	}
}

u32 get_player_choice() {
	u32 choice;
	puts("请选择：1是石头，2是布，3是剪刀");
	scanf_s("%d", &choice);

	while (choice < ROCK || choice > SCISSORS) {
		puts("无效选择！请重新选择：1是石头，2是布，3是剪刀");
		scanf_s("%d", &choice);
	}

	return choice;
}

u32 get_computer_choice() {
	return (rand() % (SCISSORS - ROCK + 1)) + ROCK;
}

void print_instructions() {

	puts("石头~剪刀~布，游戏开始！");
	puts("规则：输入数字，确定猜拳。1是石头，2是布，3是剪刀");
	puts("==========================================");
}
void print_choice(u32 choice) {
	switch (choice)
	{
	case ROCK: puts("石头"); break;
	case PAPER: puts("布"); break;
	case SCISSORS: puts("剪刀"); break;
	}
}

int main(void)
{
	//初始化随机数生成器
	srand(time(NULL));

	//打印游戏说明
	print_instructions();

	//获取玩家和计算机的选择
	u32 player_choice = get_player_choice();
	u32 computer_choice = get_computer_choice();

	//展示玩家和计算器的选择
	puts("你选择了");
	print_choice(player_choice);
	puts("计算机选择了");
	print_choice(computer_choice);

	//判断确认赢家，并且展示
	destemine_winner(player_choice, computer_choice);

	return 0;
}
